using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");
        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");
        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("12345");
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Jones");
        StringAssert.StartsWith(result, "Dear");
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Dr.");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Doe", "Dr.");
        StringAssert.Contains(result, "Dr.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!");
        StringAssert.Matches(result, new System.Text.RegularExpressions.Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetters_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("My Post Title");
        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("A Great Adventure");
        StringAssert.EndsWith(result, "adventure");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceTitle_Throws()
    {
        _formatter.GenerateSlug("  ");
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_ReturnsDollarAmount()
    {
        var result = _formatter.FormatCurrency(9.99m);
        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(42m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(10m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(5m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-3.50m);
        StringAssert.Contains(result, "-");
    }
}

